1	type Item = { type: string };
2	type Step = { op: "quote"; items: Item[] };
3	type Scenario = {
4	  customer: { yearsWithMHPCO: number };
5	  steps: Step[];
6	};
7	
8	const PROCESSING_FEE = 5;
9	const FIRST_CONTRACT_SURCHARGE_RATE = 0.1;
10	const ITEM_BASE: Record<string, number> = {
11	  sword: 100,
12	  amulet: 60,
13	  staff: 80,
14	  potion: 40,
15	  rune: 25,
16	};
17	
18	const COMPONENT_BLOCK_SIZE = 3;
19	const COMPONENT_BLOCK_BASE = 60;
20	
21	const itemBase = (item: Item): number => ITEM_BASE[item.type];
22	
23	const isComponentBlock = (items: Item[]): boolean =>
24	  items.length === COMPONENT_BLOCK_SIZE &&
25	  items.every((item) => item.type === items[0].type);
26	
27	const sumItemBases = (items: Item[]): number =>
28	  items.reduce((sum, item) => sum + itemBase(item), 0);
29	
30	const calculatePolicyBase = (items: Item[]): number =>
31	  isComponentBlock(items) ? COMPONENT_BLOCK_BASE : sumItemBases(items);
32	
33	const quotePremium = ({ items }: Step): number => {
34	  const policyBase = calculatePolicyBase(items);
35	  const firstContractSurcharge = policyBase * FIRST_CONTRACT_SURCHARGE_RATE;
36	  return Math.ceil(policyBase + firstContractSurcharge + PROCESSING_FEE);
37	};
38	
39	export const runScenario = ({ steps }: Scenario): { results: unknown[] } => {
40	  const results = steps.map((step) => ({ premium: quotePremium(step) }));
41	  return { results };
42	};
